INSERT INTO profiles (id, version, content, big_five, mbti_label, decision_style, tags, summary, quality_score, status, generation_run_id) VALUES
('9e8d2f24-8c44-4c2a-b000-980eeddd2618', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.3,"extraversion":0.67,"agreeableness":0.25,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.65,"narcissism":0.69,"psychopathy":0.58},"prospect_theory":{"lambda":0.74,"alpha":0.86,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Penny-stock gambler whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Prefers a fast wrong answer to a slow right one. Needs repeated reassurance that a decision was the right one. The instant it becomes irreversible, looks away from bad news in the hope it resolves unwitnessed; names every strategy after the trade that almost worked.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"fomo","strength":0.6},{"slug":"disposition-effect","strength":0.54},{"slug":"ostrich-effect","strength":0.63}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.95,"conscientiousness":0.3,"extraversion":0.67,"agreeableness":0.25,"neuroticism":0.67}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'Penny-stock gambler whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Prefers a fast wrong answer to a slow right one. Needs repeated reassurance that a decision was the right one. The instant it becomes irreversible, looks away from bad news in the hope it resolves unwitnessed; names every strategy after the trade that almost worked.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('2804c4c1-dd0d-4e81-a14b-0f30d3543a53', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.42,"extraversion":0.72,"agreeableness":0.26,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.64,"narcissism":0.7,"psychopathy":0.54},"prospect_theory":{"lambda":0.95,"alpha":0.81,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Jumps into whatever everyone else already seems to be winning at. A pronounced meme-coin rotator: gets bored of the proven method exactly when it starts working, hedges every commitment against an imagined worst case. Trusts a felt sense of pattern over any spreadsheet, and as a rule confuses a bull market for a trading edge.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.55},{"slug":"fomo","strength":0.71},{"slug":"recency","strength":0.69}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.42,"extraversion":0.72,"agreeableness":0.26,"neuroticism":0.66}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'Jumps into whatever everyone else already seems to be winning at. A pronounced meme-coin rotator: gets bored of the proven method exactly when it starts working, hedges every commitment against an imagined worst case. Trusts a felt sense of pattern over any spreadsheet, and as a rule confuses a bull market for a trading edge.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('9cd7cdfa-56ac-4c7b-b095-87b532164681', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.29,"extraversion":0.81,"agreeableness":0.56,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.37,"narcissism":0.62,"psychopathy":0.35},"prospect_theory":{"lambda":1.23,"alpha":0.83,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats hesitation as the bigger risk. This crypto day-trader thinks out loud and recruits an audience for every decision and reads outside the field for ideas the field itself would reject. As soon as real money or reputation is on the line is most certain precisely where their competence is thinnest — across an ordinary week, keeps a losing-trade journal they never re-read.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.63},{"slug":"dunning-kruger","strength":0.7},{"slug":"bandwagon","strength":0.62},{"slug":"herd-behavior","strength":0.6}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.74,"conscientiousness":0.29,"extraversion":0.81,"agreeableness":0.56,"neuroticism":0.62}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'Treats hesitation as the bigger risk. This crypto day-trader thinks out loud and recruits an audience for every decision and reads outside the field for ideas the field itself would reject. As soon as real money or reputation is on the line is most certain precisely where their competence is thinnest — across an ordinary week, keeps a losing-trade journal they never re-read.', 0.91, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('4a1a975c-a9c7-4b07-b8f1-c8d83d9190a3', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.89,"extraversion":0.4,"agreeableness":0.34,"neuroticism":0.19},"dark_triad":{"machiavellianism":0.78,"narcissism":0.54,"psychopathy":0.58},"prospect_theory":{"lambda":2.14,"alpha":0.91,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Index-fund holdout whose defining move is that they builds in buffer time and then fills the buffer with more work. Ranks the options twice, once on paper and once out loud, and trusts the paper. Optimizes for winning over being liked. When there is no clean exit, holds their estimates with a certainty the track record does not support; refreshes the order book compulsively during lunch.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"anchoring","strength":0.61},{"slug":"optimism","strength":0.63},{"slug":"recency","strength":0.53},{"slug":"overconfidence","strength":0.71}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.89,"extraversion":0.4,"agreeableness":0.34,"neuroticism":0.19}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament']::text[], 'Index-fund holdout whose defining move is that they builds in buffer time and then fills the buffer with more work. Ranks the options twice, once on paper and once out loud, and trusts the paper. Optimizes for winning over being liked. When there is no clean exit, holds their estimates with a certainty the track record does not support; refreshes the order book compulsively during lunch.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('7890c6a2-aefe-4e0d-a3a9-ec192a40c71a', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.61,"extraversion":0.76,"agreeableness":0.35,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.56,"narcissism":0.76,"psychopathy":0.42},"prospect_theory":{"lambda":1.09,"alpha":0.9,"beta":0.94},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A steady pairs trader who collects half-finished manifestos and unconventional methods. Builds a decision matrix for choices most people make on instinct. Treats warmth as leverage and cooperation as weakness. In a pinch takes the crowd''s confidence as a substitute for its own analysis; on an ordinary week, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.59},{"slug":"optimism","strength":0.57},{"slug":"herd-behavior","strength":0.6}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.82,"conscientiousness":0.61,"extraversion":0.76,"agreeableness":0.35,"neuroticism":0.45}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'A steady pairs trader who collects half-finished manifestos and unconventional methods. Builds a decision matrix for choices most people make on instinct. Treats warmth as leverage and cooperation as weakness. In a pinch takes the crowd''s confidence as a substitute for its own analysis; on an ordinary week, treats a green week as proof of skill and a red one as proof of bad luck.', 0.92, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('e089e480-fbd9-4b9c-91e6-fa4c05dd9cdf', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.44,"extraversion":0.55,"agreeableness":0.59,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.4,"narcissism":0.31,"psychopathy":0.32},"prospect_theory":{"lambda":3.24,"alpha":0.75,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Judges likelihood by how easily an example comes to mind, not by the base rate. A pronounced perps degen: carries yesterday''s stress into today''s unrelated decision. Treats not-choosing as a safe choice right up until it is not, and in the routine of it keeps three monitors for a portfolio that fits on one screen.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.64},{"slug":"availability","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.52,"conscientiousness":0.44,"extraversion":0.55,"agreeableness":0.59,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Judges likelihood by how easily an example comes to mind, not by the base rate. A pronounced perps degen: carries yesterday''s stress into today''s unrelated decision. Treats not-choosing as a safe choice right up until it is not, and in the routine of it keeps three monitors for a portfolio that fits on one screen.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('84d1ebd1-0929-45a0-b0c2-d07569fd2efb', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.31,"extraversion":0.8,"agreeableness":0.36,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.53,"narcissism":0.77,"psychopathy":0.46},"prospect_theory":{"lambda":0.92,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Penny-stock gambler whose defining move is that they would rather invent a worse tool than use someone else''s good one. Lets pattern-matching from past cases stand in for fresh analysis. Assumes self-interest in others because it is usually there in themselves. The moment risk appears, mistakes a little fluency for real mastery; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"fomo","strength":0.62}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.31,"extraversion":0.8,"agreeableness":0.36,"neuroticism":0.57}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'Penny-stock gambler whose defining move is that they would rather invent a worse tool than use someone else''s good one. Lets pattern-matching from past cases stand in for fresh analysis. Assumes self-interest in others because it is usually there in themselves. The moment risk appears, mistakes a little fluency for real mastery; treats a green week as proof of skill and a red one as proof of bad luck.', 0.95, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('073caa50-31b2-4d52-b083-764e2352bf44', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.33,"extraversion":0.58,"agreeableness":0.53,"neuroticism":0.95},"dark_triad":{"machiavellianism":0.42,"narcissism":0.28,"psychopathy":0.38},"prospect_theory":{"lambda":3.53,"alpha":0.73,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"As soon as real money or reputation is on the line, will give up a good bet just to avoid the chance of a bad one. Otherwise, a pronounced penny-stock gambler who reads a single setback as evidence of collapse and is reliably surprised by deadlines that were never hidden. Buries hard calls under a pile of preparatory busywork, and in the pattern nobody else tracks calls a 90% drawdown a long-term hold.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.71},{"slug":"loss-aversion","strength":0.78},{"slug":"ostrich-effect","strength":0.75}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.54,"conscientiousness":0.33,"extraversion":0.58,"agreeableness":0.53,"neuroticism":0.95}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'As soon as real money or reputation is on the line, will give up a good bet just to avoid the chance of a bad one. Otherwise, a pronounced penny-stock gambler who reads a single setback as evidence of collapse and is reliably surprised by deadlines that were never hidden. Buries hard calls under a pile of preparatory busywork, and in the pattern nobody else tracks calls a 90% drawdown a long-term hold.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('9474a82e-cbfe-4c8f-9561-72678d046a9a', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.31,"extraversion":0.79,"agreeableness":0.67,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.4,"narcissism":0.63,"psychopathy":0.37},"prospect_theory":{"lambda":1.1,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Trusts momentum over preparation. This liquidation-bot operator collects half-finished manifestos and unconventional methods and spirals on ambiguity and mistakes the spiral for diligence. When there is no clean exit jumps into whatever everyone else already seems to be winning at — day to day, sizes every position at exactly 2% risk.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.72},{"slug":"bandwagon","strength":0.65},{"slug":"herd-behavior","strength":0.65},{"slug":"recency","strength":0.66}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.86,"conscientiousness":0.31,"extraversion":0.79,"agreeableness":0.67,"neuroticism":0.65}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded']::text[], 'Trusts momentum over preparation. This liquidation-bot operator collects half-finished manifestos and unconventional methods and spirals on ambiguity and mistakes the spiral for diligence. When there is no clean exit jumps into whatever everyone else already seems to be winning at — day to day, sizes every position at exactly 2% risk.', 0.94, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('51b9a87f-f61f-4305-8e43-4c27bfada4b8', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.85,"extraversion":0.47,"agreeableness":0.25,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.85,"narcissism":0.62,"psychopathy":0.61},"prospect_theory":{"lambda":2.22,"alpha":0.92,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"The instant the deadline moves up, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced bonding-curve sniper who front-loads the work and double-checks it twice and negotiates every relationship a little, even the close ones. Builds a decision matrix for choices most people make on instinct, and on a slow afternoon sizes every position at exactly 2% risk.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.57},{"slug":"overconfidence","strength":0.7},{"slug":"hindsight","strength":0.62},{"slug":"recency","strength":0.59}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.72,"conscientiousness":0.85,"extraversion":0.47,"agreeableness":0.25,"neuroticism":0.35}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making']::text[], 'The instant the deadline moves up, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced bonding-curve sniper who front-loads the work and double-checks it twice and negotiates every relationship a little, even the close ones. Builds a decision matrix for choices most people make on instinct, and on a slow afternoon sizes every position at exactly 2% risk.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('be1c5c6e-d6e3-4d8d-8268-72e4cbca5f40', 1, '{"big_five":{"openness":0.42,"conscientiousness":0.52,"extraversion":0.4,"agreeableness":0.55,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.39,"narcissism":0.36,"psychopathy":0.33},"prospect_theory":{"lambda":3,"alpha":0.88,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A measured penny-stock gambler who weighs words carefully before spending them. Outsources conviction to whoever spoke last with authority. Once the exit narrows to one door treats the default option as the safe one by default, not by analysis; across an ordinary week, keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ISFJ","suggested_biases":[{"slug":"status-quo","strength":0.52},{"slug":"anchoring","strength":0.46}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.42,"conscientiousness":0.52,"extraversion":0.4,"agreeableness":0.55,"neuroticism":0.45}'::jsonb, 'ISFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'A measured penny-stock gambler who weighs words carefully before spending them. Outsources conviction to whoever spoke last with authority. Once the exit narrows to one door treats the default option as the safe one by default, not by analysis; across an ordinary week, keeps three monitors for a portfolio that fits on one screen.', 0.83, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('88c3a123-1152-417b-b4c3-966096122eab', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.41,"extraversion":0.77,"agreeableness":0.67,"neuroticism":0.75},"dark_triad":{"machiavellianism":0.38,"narcissism":0.59,"psychopathy":0.36},"prospect_theory":{"lambda":1.03,"alpha":0.79,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Index-fund holdout, steady in style: treats established procedure as a first draft to be rewritten; would rather lose a point than win an argument badly. Trusts momentum over preparation. Under pressure assumes the current streak is the new normal.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.74},{"slug":"fomo","strength":0.72}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.8,"conscientiousness":0.41,"extraversion":0.77,"agreeableness":0.67,"neuroticism":0.75}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded']::text[], 'Index-fund holdout, steady in style: treats established procedure as a first draft to be rewritten; would rather lose a point than win an argument badly. Trusts momentum over preparation. Under pressure assumes the current streak is the new normal.', 0.92, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
