('fe75f3e7-d99b-4e7d-8e36-a2ad03fc1931', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.86,"extraversion":0.5,"agreeableness":0.36,"neuroticism":0.21},"dark_triad":{"machiavellianism":0.8,"narcissism":0.54,"psychopathy":0.6},"prospect_theory":{"lambda":2.19,"alpha":0.89,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Perps degen, pronounced in style: maintains flawless records nobody asked for; gets bored of the proven method exactly when it starts working. Weighs options against explicit criteria and distrusts anything they cannot tabulate. The instant it becomes irreversible holds their estimates with a certainty the track record does not support.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.64},{"slug":"recency","strength":0.52},{"slug":"overconfidence","strength":0.65}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.86,"extraversion":0.5,"agreeableness":0.36,"neuroticism":0.21}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament']::text[], 'Perps degen, pronounced in style: maintains flawless records nobody asked for; gets bored of the proven method exactly when it starts working. Weighs options against explicit criteria and distrusts anything they cannot tabulate. The instant it becomes irreversible holds their estimates with a certainty the track record does not support.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('55b58bf4-794c-49de-a1fb-35a926b643eb', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.34,"extraversion":0.73,"agreeableness":0.39,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.47,"narcissism":0.67,"psychopathy":0.42},"prospect_theory":{"lambda":1.05,"alpha":0.9,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Futures spreader whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Prefers a fast wrong answer to a slow right one. Improvises past every deadline and calls it flexibility. As soon as real money or reputation is on the line, mistakes a little fluency for real mastery; screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"bandwagon","strength":0.55},{"slug":"herd-behavior","strength":0.62},{"slug":"recency","strength":0.63},{"slug":"dunning-kruger","strength":0.69}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.83,"conscientiousness":0.34,"extraversion":0.73,"agreeableness":0.39,"neuroticism":0.52}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'Futures spreader whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Prefers a fast wrong answer to a slow right one. Improvises past every deadline and calls it flexibility. As soon as real money or reputation is on the line, mistakes a little fluency for real mastery; screenshots the winners and never the losers.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('fd9a93b2-a173-448e-bf4c-7002bfeba2ea', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.39,"extraversion":0.76,"agreeableness":0.36,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.52,"narcissism":0.79,"psychopathy":0.44},"prospect_theory":{"lambda":1,"alpha":0.92,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Discounts the older pattern in favor of whatever just happened. A pronounced volatility arbitrageur: chases novel frameworks and abandons them once the novelty fades, would rather be respected than liked, and says so. Lets pattern-matching from past cases stand in for fresh analysis, and in the unglamorous middle of things sets stop-losses then cancels them at the open.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"bandwagon","strength":0.61},{"slug":"recency","strength":0.66},{"slug":"dunning-kruger","strength":0.61},{"slug":"fomo","strength":0.57}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.87,"conscientiousness":0.39,"extraversion":0.76,"agreeableness":0.36,"neuroticism":0.5}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'Discounts the older pattern in favor of whatever just happened. A pronounced volatility arbitrageur: chases novel frameworks and abandons them once the novelty fades, would rather be respected than liked, and says so. Lets pattern-matching from past cases stand in for fresh analysis, and in the unglamorous middle of things sets stop-losses then cancels them at the open.', 0.94, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('2f6b0286-6cbd-425e-bda2-9373749cc4ec', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.33,"extraversion":0.61,"agreeableness":0.67,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.39,"narcissism":0.44,"psychopathy":0.37},"prospect_theory":{"lambda":3.51,"alpha":0.74,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced futures spreader who notices the one thing that could go wrong before the nine that could go right. Defers the decision until circumstances make it for them. Reads outside the field for ideas the field itself would reject. Once the exit narrows to one door delays checking the number it most needs to check; without an audience, holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.67},{"slug":"ostrich-effect","strength":0.75},{"slug":"availability","strength":0.64},{"slug":"recency","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.75,"conscientiousness":0.33,"extraversion":0.61,"agreeableness":0.67,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'A pronounced futures spreader who notices the one thing that could go wrong before the nine that could go right. Defers the decision until circumstances make it for them. Reads outside the field for ideas the field itself would reject. Once the exit narrows to one door delays checking the number it most needs to check; without an audience, holds a bag from 2021 out of pure spite.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
