('8a27acc6-6f3e-4495-8866-8a9a160fb5b5', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.35,"extraversion":0.74,"agreeableness":0.2,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.7,"narcissism":0.86,"psychopathy":0.57},"prospect_theory":{"lambda":0.79,"alpha":0.85,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the downside gets concrete, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced value investor who gets bored of the proven method exactly when it starts working and leaves loose ends and trusts future-self to handle them. Moves first and rationalizes second, usually convincingly, and across the quiet stretches backtests for months but front-runs the model on impulse.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.59},{"slug":"recency","strength":0.73},{"slug":"overconfidence","strength":0.65}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.35,"extraversion":0.74,"agreeableness":0.2,"neuroticism":0.58}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'When the downside gets concrete, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced value investor who gets bored of the proven method exactly when it starts working and leaves loose ends and trusts future-self to handle them. Moves first and rationalizes second, usually convincingly, and across the quiet stretches backtests for months but front-runs the model on impulse.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
