('b1c8a039-b57b-4287-be14-832b7fd42d2b', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.5,"extraversion":0.73,"agreeableness":0.39,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.48,"narcissism":0.7,"psychopathy":0.4},"prospect_theory":{"lambda":1.11,"alpha":0.86,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Macro allocator whose defining move is that they gets bored of the proven method exactly when it starts working. Treats a decision without a paper trail as a decision not yet made. Narrates the plan to whoever is nearby before committing to it. Once things get tense, finds it hard to hold a contrarian position once the room disagrees; checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"herd-behavior","strength":0.62},{"slug":"recency","strength":0.56}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.5,"extraversion":0.73,"agreeableness":0.39,"neuroticism":0.52}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Macro allocator whose defining move is that they gets bored of the proven method exactly when it starts working. Treats a decision without a paper trail as a decision not yet made. Narrates the plan to whoever is nearby before committing to it. Once things get tense, finds it hard to hold a contrarian position once the room disagrees; checks the P&L blotter forty times before lunch.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('b39a5251-5240-430a-b315-24d7c277c380', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.94,"extraversion":0.46,"agreeableness":0.34,"neuroticism":0.15},"dark_triad":{"machiavellianism":0.84,"narcissism":0.51,"psychopathy":0.66},"prospect_theory":{"lambda":2.16,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Underestimates how often an obviously right call turns out wrong. A pronounced perps degen: cannot relax until the checklist is visibly complete, gets bored of the proven method exactly when it starts working. Ranks the options twice, once on paper and once out loud, and trusts the paper, and on a slow afternoon rotates the whole book into whatever is pumping this hour.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.68},{"slug":"anchoring","strength":0.57},{"slug":"optimism","strength":0.67}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","behavioral"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.94,"extraversion":0.46,"agreeableness":0.34,"neuroticism":0.15}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','behavioral']::text[], 'Underestimates how often an obviously right call turns out wrong. A pronounced perps degen: cannot relax until the checklist is visibly complete, gets bored of the proven method exactly when it starts working. Ranks the options twice, once on paper and once out loud, and trusts the paper, and on a slow afternoon rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
