('bba5f6d8-5ed3-4fad-a56e-d5295367aef3', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.52,"extraversion":0.51,"agreeableness":0.7,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.39,"narcissism":0.36,"psychopathy":0.26},"prospect_theory":{"lambda":2.95,"alpha":0.87,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Delta-neutral market maker whose defining move is that they apologizes first in disputes regardless of fault. Waits for a permission that never quite arrives. Under a deadline, abandons a private read the instant the crowd leans the other way; keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.59},{"slug":"endowment","strength":0.53},{"slug":"authority-bias","strength":0.55},{"slug":"sunk-cost","strength":0.58}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.51,"conscientiousness":0.52,"extraversion":0.51,"agreeableness":0.7,"neuroticism":0.53}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Delta-neutral market maker whose defining move is that they apologizes first in disputes regardless of fault. Waits for a permission that never quite arrives. Under a deadline, abandons a private read the instant the crowd leans the other way; keeps a losing-trade journal they never re-read.', 0.85, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
