('a261008b-46f8-406d-b0d7-171fe3bea180', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.4,"extraversion":0.71,"agreeableness":0.57,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.39,"narcissism":0.54,"psychopathy":0.32},"prospect_theory":{"lambda":1.13,"alpha":0.82,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Acts on the midnight epiphany and emails it at 1am. This quant researcher collects half-finished manifestos and unconventional methods and fills silence reflexively, even when nobody asked it to. The moment risk appears takes the crowd''s confidence as a substitute for its own analysis — when no one is watching, talks in win rate and never mentions size.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.63},{"slug":"recency","strength":0.6}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.77,"conscientiousness":0.4,"extraversion":0.71,"agreeableness":0.57,"neuroticism":0.7}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded']::text[], 'Acts on the midnight epiphany and emails it at 1am. This quant researcher collects half-finished manifestos and unconventional methods and fills silence reflexively, even when nobody asked it to. The moment risk appears takes the crowd''s confidence as a substitute for its own analysis — when no one is watching, talks in win rate and never mentions size.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('fb9e6e8c-42b0-445d-b21c-c7ded831642d', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.41,"extraversion":0.79,"agreeableness":0.66,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.37,"narcissism":0.64,"psychopathy":0.33},"prospect_theory":{"lambda":1.24,"alpha":0.83,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Pairs trader, pronounced in style: chases novel frameworks and abandons them once the novelty fades; needs repeated reassurance that a decision was the right one. Decides in the time it takes to say the decision out loud. The moment it stops being hypothetical extrapolates the last data point into a permanent trend.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.7},{"slug":"herd-behavior","strength":0.67}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.85,"conscientiousness":0.41,"extraversion":0.79,"agreeableness":0.66,"neuroticism":0.69}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded']::text[], 'Pairs trader, pronounced in style: chases novel frameworks and abandons them once the novelty fades; needs repeated reassurance that a decision was the right one. Decides in the time it takes to say the decision out loud. The moment it stops being hypothetical extrapolates the last data point into a permanent trend.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
