('eab9592e-f038-451e-a27b-4ba3594a7af3', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.37,"extraversion":0.67,"agreeableness":0.56,"neuroticism":0.86},"dark_triad":{"machiavellianism":0.39,"narcissism":0.4,"psychopathy":0.33},"prospect_theory":{"lambda":3.52,"alpha":0.78,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced pairs trader who reads a single setback as evidence of collapse. Prefers a slow loss to a fast, ownable mistake. Treats a plan as a suggestion the moment it is made. The moment it stops being hypothetical assumes the current streak is the new normal; in the pattern nobody else tracks, sets alerts for a coin they already checked a minute ago.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"recency","strength":0.72},{"slug":"disposition-effect","strength":0.67},{"slug":"loss-aversion","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.62,"conscientiousness":0.37,"extraversion":0.67,"agreeableness":0.56,"neuroticism":0.86}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'A pronounced pairs trader who reads a single setback as evidence of collapse. Prefers a slow loss to a fast, ownable mistake. Treats a plan as a suggestion the moment it is made. The moment it stops being hypothetical assumes the current streak is the new normal; in the pattern nobody else tracks, sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
