('de092b1b-35b7-4c30-b5d7-72fba31553b2', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.29,"extraversion":0.81,"agreeableness":0.2,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.69,"narcissism":0.88,"psychopathy":0.65},"prospect_theory":{"lambda":0.94,"alpha":0.87,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced macro allocator who reads outside the field for ideas the field itself would reject and fills silence reflexively, even when nobody asked it to. Treats hesitation as the bigger risk, and once the urgency drains out talks in win rate and never mentions size.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.7},{"slug":"dunning-kruger","strength":0.67},{"slug":"fomo","strength":0.67}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.29,"extraversion":0.81,"agreeableness":0.2,"neuroticism":0.57}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'When the safe option quietly expires, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced macro allocator who reads outside the field for ideas the field itself would reject and fills silence reflexively, even when nobody asked it to. Treats hesitation as the bigger risk, and once the urgency drains out talks in win rate and never mentions size.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
