('e20ad707-7527-4326-b0f3-f0975f532bcd', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.51,"extraversion":0.77,"agreeableness":0.32,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.57,"narcissism":0.83,"psychopathy":0.51},"prospect_theory":{"lambda":1.07,"alpha":0.83,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Assumes the current streak is the new normal. A pronounced MEV searcher: reads outside the field for ideas the field itself would reject, treats consensus-seeking as a waste of time. Demands the data before the discussion and the discussion before the call, and left to their own devices checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.6},{"slug":"fomo","strength":0.65},{"slug":"recency","strength":0.67},{"slug":"herd-behavior","strength":0.67}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.9,"conscientiousness":0.51,"extraversion":0.77,"agreeableness":0.32,"neuroticism":0.41}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Assumes the current streak is the new normal. A pronounced MEV searcher: reads outside the field for ideas the field itself would reject, treats consensus-seeking as a waste of time. Demands the data before the discussion and the discussion before the call, and left to their own devices checks the P&L blotter forty times before lunch.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('02848e8c-0d3f-4962-a611-27422e1d7738', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.34,"extraversion":0.54,"agreeableness":0.62,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.41,"narcissism":0.37,"psychopathy":0.39},"prospect_theory":{"lambda":3.5,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Zero-DTE options gambler, steady in style: reads a single setback as evidence of collapse; confuses motion with progress. Treats not-choosing as a safe choice right up until it is not. When someone is watching the outcome assumes the current streak is the new normal.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.64},{"slug":"framing","strength":0.6},{"slug":"sunk-cost","strength":0.57},{"slug":"ostrich-effect","strength":0.6}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.57,"conscientiousness":0.34,"extraversion":0.54,"agreeableness":0.62,"neuroticism":0.71}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Zero-DTE options gambler, steady in style: reads a single setback as evidence of collapse; confuses motion with progress. Treats not-choosing as a safe choice right up until it is not. When someone is watching the outcome assumes the current streak is the new normal.', 0.91, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('9b3ccd7b-e6f7-4312-90ef-1268b9a1fb63', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.32,"extraversion":0.8,"agreeableness":0.28,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.61,"narcissism":0.83,"psychopathy":0.53},"prospect_theory":{"lambda":1.06,"alpha":0.86,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced pairs trader who would rather invent a worse tool than use someone else''s good one. Prefers a fast wrong answer to a slow right one. Optimizes for winning over being liked. In a pinch discounts the older pattern in favor of whatever just happened; in the parts nobody grades, exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"herd-behavior","strength":0.59},{"slug":"recency","strength":0.7},{"slug":"dunning-kruger","strength":0.66}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.32,"extraversion":0.8,"agreeableness":0.28,"neuroticism":0.58}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'A pronounced pairs trader who would rather invent a worse tool than use someone else''s good one. Prefers a fast wrong answer to a slow right one. Optimizes for winning over being liked. In a pinch discounts the older pattern in favor of whatever just happened; in the parts nobody grades, exits winners at the first green candle.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('295142b2-57d9-4f14-a7d9-ea161d472925', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.54,"extraversion":0.62,"agreeableness":0.43,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.51,"narcissism":0.65,"psychopathy":0.38},"prospect_theory":{"lambda":1.35,"alpha":0.84,"beta":0.96},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Algorithmic market-maker whose defining move is that they treats established procedure as a first draft to be rewritten. Treats a decision without a paper trail as a decision not yet made. Narrates the plan to whoever is nearby before committing to it. As soon as real money or reputation is on the line, discounts the older pattern in favor of whatever just happened; exits winners at the first green candle.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"optimism","strength":0.51}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.96,"conscientiousness":0.54,"extraversion":0.62,"agreeableness":0.43,"neuroticism":0.45}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Algorithmic market-maker whose defining move is that they treats established procedure as a first draft to be rewritten. Treats a decision without a paper trail as a decision not yet made. Narrates the plan to whoever is nearby before committing to it. As soon as real money or reputation is on the line, discounts the older pattern in favor of whatever just happened; exits winners at the first green candle.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
