('8dfa6556-64a0-46f7-a601-2b73cb1075a9', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.56,"extraversion":0.74,"agreeableness":0.29,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.62,"narcissism":0.76,"psychopathy":0.47},"prospect_theory":{"lambda":0.79,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator whose defining move is that they treats established procedure as a first draft to be rewritten. Reads a room or a market the way others read a paragraph. Thinks out loud and recruits an audience for every decision. Under pressure, takes the crowd''s confidence as a substitute for its own analysis; screenshots the winners and never the losers.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"herd-behavior","strength":0.58},{"slug":"fomo","strength":0.58}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.56,"extraversion":0.74,"agreeableness":0.29,"neuroticism":0.55}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'Liquidation-bot operator whose defining move is that they treats established procedure as a first draft to be rewritten. Reads a room or a market the way others read a paragraph. Thinks out loud and recruits an audience for every decision. Under pressure, takes the crowd''s confidence as a substitute for its own analysis; screenshots the winners and never the losers.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
