('33756b25-3efd-4c8a-bc7b-c49b85d67788', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.3,"extraversion":0.71,"agreeableness":0.29,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.6,"narcissism":0.77,"psychopathy":0.56},"prospect_theory":{"lambda":0.99,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator whose defining move is that they would rather invent a worse tool than use someone else''s good one. Acts on the midnight epiphany and emails it at 1am. Optimizes for winning over being liked. When the number turns red, assumes the current streak is the new normal; backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.56},{"slug":"overconfidence","strength":0.58},{"slug":"fomo","strength":0.59},{"slug":"recency","strength":0.69}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.96,"conscientiousness":0.3,"extraversion":0.71,"agreeableness":0.29,"neuroticism":0.53}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'Meme-coin rotator whose defining move is that they would rather invent a worse tool than use someone else''s good one. Acts on the midnight epiphany and emails it at 1am. Optimizes for winning over being liked. When the number turns red, assumes the current streak is the new normal; backtests for months but front-runs the model on impulse.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
