('4a3d82c6-c929-43aa-a539-76ed87673bdb', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.59,"extraversion":0.6,"agreeableness":0.61,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.46,"narcissism":0.45,"psychopathy":0.26},"prospect_theory":{"lambda":2.83,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A measured discretionary swing trader who reads outside the field for ideas the field itself would reject. Needs the room''s approval more than it needs to be right. When the stakes rise finds it hard to hold a contrarian position once the room disagrees; day to day, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.46},{"slug":"bandwagon","strength":0.51},{"slug":"herd-behavior","strength":0.53}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.61,"conscientiousness":0.59,"extraversion":0.6,"agreeableness":0.61,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'A measured discretionary swing trader who reads outside the field for ideas the field itself would reject. Needs the room''s approval more than it needs to be right. When the stakes rise finds it hard to hold a contrarian position once the room disagrees; day to day, refreshes the order book compulsively during lunch.', 0.82, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
