('d1a33c57-a2e1-421f-a2a5-0d42666dcc6a', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.58,"extraversion":0.47,"agreeableness":0.62,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.46,"narcissism":0.39,"psychopathy":0.27},"prospect_theory":{"lambda":2.96,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This value investor takes on other people''s problems as if they were their own. In a pinch second-guesses its own read the moment someone senior disagrees — in the parts nobody grades, checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"bandwagon","strength":0.48},{"slug":"authority-bias","strength":0.51}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.55,"conscientiousness":0.58,"extraversion":0.47,"agreeableness":0.62,"neuroticism":0.58}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This value investor takes on other people''s problems as if they were their own. In a pinch second-guesses its own read the moment someone senior disagrees — in the parts nobody grades, checks the P&L blotter forty times before lunch.', 0.83, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
