('3f93a29b-ea7d-4d17-8d36-e77b267f18c3', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.39,"extraversion":0.59,"agreeableness":0.64,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.4,"narcissism":0.37,"psychopathy":0.29},"prospect_theory":{"lambda":3.43,"alpha":0.76,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Locks in small wins fast and rides large losses far past the point of sense. A steady options seller: notices the one thing that could go wrong before the nine that could go right, absorbs conflict to keep the peace, often at their own cost. Defers the decision until circumstances make it for them, and left to their own devices exits winners at the first green candle.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.66},{"slug":"ostrich-effect","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.61,"conscientiousness":0.39,"extraversion":0.59,"agreeableness":0.64,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Locks in small wins fast and rides large losses far past the point of sense. A steady options seller: notices the one thing that could go wrong before the nine that could go right, absorbs conflict to keep the peace, often at their own cost. Defers the decision until circumstances make it for them, and left to their own devices exits winners at the first green candle.', 0.95, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
