('eaed06e2-f088-4407-bad1-0e02b4dc0bb8', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.4,"extraversion":0.61,"agreeableness":0.6,"neuroticism":0.75},"dark_triad":{"machiavellianism":0.41,"narcissism":0.37,"psychopathy":0.36},"prospect_theory":{"lambda":3.39,"alpha":0.82,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the stakes rise, cannot watch a rally from the sidelines for long. Otherwise, a steady pairs trader who rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them, and day to day trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.62},{"slug":"disposition-effect","strength":0.59},{"slug":"availability","strength":0.62},{"slug":"ostrich-effect","strength":0.57}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.54,"conscientiousness":0.4,"extraversion":0.61,"agreeableness":0.6,"neuroticism":0.75}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'When the stakes rise, cannot watch a rally from the sidelines for long. Otherwise, a steady pairs trader who rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them, and day to day trusts the chart more than the fundamentals and won''t say why.', 0.87, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
