('e09df34a-7494-41f4-89a0-948230bf11ef', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.24,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.64,"narcissism":0.83,"psychopathy":0.58},"prospect_theory":{"lambda":0.76,"alpha":0.85,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady pairs trader who reads outside the field for ideas the field itself would reject. Prefers a fast wrong answer to a slow right one. Treats a plan as a suggestion the moment it is made. Once things get tense cannot watch a rally from the sidelines for long; in the small things, keeps a losing-trade journal they never re-read.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.64},{"slug":"fomo","strength":0.68}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.81,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.24,"neuroticism":0.57}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'A steady pairs trader who reads outside the field for ideas the field itself would reject. Prefers a fast wrong answer to a slow right one. Treats a plan as a suggestion the moment it is made. Once things get tense cannot watch a rally from the sidelines for long; in the small things, keeps a losing-trade journal they never re-read.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('e1b88ffd-57e4-469d-b548-289994539ad4', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.35,"extraversion":0.91,"agreeableness":0.57,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.44,"narcissism":0.7,"psychopathy":0.36},"prospect_theory":{"lambda":1.02,"alpha":0.8,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Once things get tense, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced dividend-yield chaser who treats a quiet room as a problem to be solved and chases novel frameworks and abandons them once the novelty fades. Commits before the doubt has time to organize itself, and in the parts nobody grades holds a bag from 2021 out of pure spite.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.59},{"slug":"bandwagon","strength":0.64},{"slug":"herd-behavior","strength":0.68},{"slug":"fomo","strength":0.73}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.7,"conscientiousness":0.35,"extraversion":0.91,"agreeableness":0.57,"neuroticism":0.65}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'Once things get tense, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced dividend-yield chaser who treats a quiet room as a problem to be solved and chases novel frameworks and abandons them once the novelty fades. Commits before the doubt has time to organize itself, and in the parts nobody grades holds a bag from 2021 out of pure spite.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('96e46083-6f2c-4c96-86be-215b5b977f2a', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.27,"extraversion":0.66,"agreeableness":0.61,"neuroticism":0.93},"dark_triad":{"machiavellianism":0.38,"narcissism":0.41,"psychopathy":0.42},"prospect_theory":{"lambda":3.45,"alpha":0.78,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Discretionary swing trader, pronounced in style: reads a single setback as evidence of collapse; confuses motion with progress. Buries hard calls under a pile of preparatory busywork. The moment risk appears looks away from bad news in the hope it resolves unwitnessed.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.68},{"slug":"fomo","strength":0.68},{"slug":"ostrich-effect","strength":0.8},{"slug":"availability","strength":0.72}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.6,"conscientiousness":0.27,"extraversion":0.66,"agreeableness":0.61,"neuroticism":0.93}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Discretionary swing trader, pronounced in style: reads a single setback as evidence of collapse; confuses motion with progress. Buries hard calls under a pile of preparatory busywork. The moment risk appears looks away from bad news in the hope it resolves unwitnessed.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('9101362d-0217-4290-8762-175ef18b3f70', 1, '{"big_five":{"openness":0.47,"conscientiousness":0.63,"extraversion":0.52,"agreeableness":0.64,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.44,"narcissism":0.41,"psychopathy":0.31},"prospect_theory":{"lambda":2.73,"alpha":0.94,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A measured airdrop farmer who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. Maintains flawless records nobody asked for. When the walls close in second-guesses its own read the moment someone senior disagrees; in the routine of it, trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ESFJ","suggested_biases":[{"slug":"bandwagon","strength":0.5},{"slug":"authority-bias","strength":0.57}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.47,"conscientiousness":0.63,"extraversion":0.52,"agreeableness":0.64,"neuroticism":0.44}'::jsonb, 'ESFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'A measured airdrop farmer who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. Maintains flawless records nobody asked for. When the walls close in second-guesses its own read the moment someone senior disagrees; in the routine of it, trusts the chart more than the fundamentals and won''t say why.', 0.82, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('9e5cff29-0e3e-48ea-b1dd-d74fe64f1881', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.59,"extraversion":0.55,"agreeableness":0.35,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.59,"narcissism":0.6,"psychopathy":0.38},"prospect_theory":{"lambda":1.06,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Converts every argument into a number it can compare against another number. This liquidation-bot operator gets bored of the proven method exactly when it starts working and would rather be respected than liked, and says so. When there is no clean exit extrapolates the last data point into a permanent trend — in the routine of it, checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"hindsight","strength":0.57},{"slug":"recency","strength":0.6},{"slug":"fomo","strength":0.48}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.59,"extraversion":0.55,"agreeableness":0.35,"neuroticism":0.49}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Converts every argument into a number it can compare against another number. This liquidation-bot operator gets bored of the proven method exactly when it starts working and would rather be respected than liked, and says so. When there is no clean exit extrapolates the last data point into a permanent trend — in the routine of it, checks the P&L blotter forty times before lunch.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
