('0c4c0d90-f0ac-44f2-815d-124352e98a24', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.28,"extraversion":0.82,"agreeableness":0.29,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.62,"narcissism":0.83,"psychopathy":0.52},"prospect_theory":{"lambda":0.99,"alpha":0.93,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced airdrop farmer who reframes every problem as an excuse to learn a new system. Trusts momentum over preparation. Assumes self-interest in others because it is usually there in themselves. When the downside gets concrete is most certain precisely where their competence is thinnest; left to their own devices, checks the P&L blotter forty times before lunch.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"fomo","strength":0.66},{"slug":"dunning-kruger","strength":0.76}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.9,"conscientiousness":0.28,"extraversion":0.82,"agreeableness":0.29,"neuroticism":0.51}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'A pronounced airdrop farmer who reframes every problem as an excuse to learn a new system. Trusts momentum over preparation. Assumes self-interest in others because it is usually there in themselves. When the downside gets concrete is most certain precisely where their competence is thinnest; left to their own devices, checks the P&L blotter forty times before lunch.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('46567dca-a8f0-4156-895d-94792ed953f5', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.55,"extraversion":0.49,"agreeableness":0.67,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.39,"narcissism":0.34,"psychopathy":0.29},"prospect_theory":{"lambda":2.94,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under a deadline, second-guesses its own read the moment someone senior disagrees. Otherwise, a steady index-fund holdout who apologizes first in disputes regardless of fault. Circles back to ask what someone else would do even after deciding, and in the routine of it rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.5},{"slug":"sunk-cost","strength":0.56},{"slug":"authority-bias","strength":0.59},{"slug":"endowment","strength":0.54}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.53,"conscientiousness":0.55,"extraversion":0.49,"agreeableness":0.67,"neuroticism":0.6}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Under a deadline, second-guesses its own read the moment someone senior disagrees. Otherwise, a steady index-fund holdout who apologizes first in disputes regardless of fault. Circles back to ask what someone else would do even after deciding, and in the routine of it rotates the whole book into whatever is pumping this hour.', 0.88, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('2d1b43b8-f4b5-43f3-8e1f-24dd6166681d', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.92,"extraversion":0.37,"agreeableness":0.34,"neuroticism":0.3},"dark_triad":{"machiavellianism":0.8,"narcissism":0.58,"psychopathy":0.52},"prospect_theory":{"lambda":2.25,"alpha":0.96,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"The instant the deadline moves up, is more certain than the hit rate justifies. Otherwise, a pronounced retail momentum chaser who plans in exhaustive detail and resents any deviation and chases novel frameworks and abandons them once the novelty fades. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and across the quiet stretches calls a 90% drawdown a long-term hold.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.65},{"slug":"recency","strength":0.56},{"slug":"anchoring","strength":0.61}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.82,"conscientiousness":0.92,"extraversion":0.37,"agreeableness":0.34,"neuroticism":0.3}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament']::text[], 'The instant the deadline moves up, is more certain than the hit rate justifies. Otherwise, a pronounced retail momentum chaser who plans in exhaustive detail and resents any deviation and chases novel frameworks and abandons them once the novelty fades. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and across the quiet stretches calls a 90% drawdown a long-term hold.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
