('cce1c8a6-eb1e-415f-af7e-3ac685db4cc5', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.44,"extraversion":0.47,"agreeableness":0.69,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.38,"narcissism":0.39,"psychopathy":0.3},"prospect_theory":{"lambda":3.05,"alpha":0.86,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Would not buy back what it already owns at the price it would sell it for. A steady MEV searcher: apologizes first in disputes regardless of fault. Seeks a second, third, and fourth opinion before committing to anything, and when the stakes are trivial names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"INFP","suggested_biases":[{"slug":"sunk-cost","strength":0.52},{"slug":"endowment","strength":0.57},{"slug":"herd-behavior","strength":0.5},{"slug":"authority-bias","strength":0.5}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.55,"conscientiousness":0.44,"extraversion":0.47,"agreeableness":0.69,"neuroticism":0.55}'::jsonb, 'INFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Would not buy back what it already owns at the price it would sell it for. A steady MEV searcher: apologizes first in disputes regardless of fault. Seeks a second, third, and fourth opinion before committing to anything, and when the stakes are trivial names every strategy after the trade that almost worked.', 0.89, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('e28150a3-6ee3-4aa8-8963-5e45e7984f53', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.39,"extraversion":0.5,"agreeableness":0.43,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.52,"narcissism":0.34,"psychopathy":0.39},"prospect_theory":{"lambda":3.29,"alpha":0.78,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"The instant the deadline moves up, sells the winners early and clings to the losers for far too long. Otherwise, a steady delta-neutral market maker who carries yesterday''s stress into today''s unrelated decision. Lets the deadline make the decision by default, and without an audience screenshots the winners and never the losers.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"disposition-effect","strength":0.62},{"slug":"ostrich-effect","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.51,"conscientiousness":0.39,"extraversion":0.5,"agreeableness":0.43,"neuroticism":0.8}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'The instant the deadline moves up, sells the winners early and clings to the losers for far too long. Otherwise, a steady delta-neutral market maker who carries yesterday''s stress into today''s unrelated decision. Lets the deadline make the decision by default, and without an audience screenshots the winners and never the losers.', 0.93, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('046922dd-304c-4d09-a664-f9b87801394e', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.43,"extraversion":0.64,"agreeableness":0.69,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.35,"narcissism":0.43,"psychopathy":0.28},"prospect_theory":{"lambda":0.97,"alpha":0.81,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats hesitation as the bigger risk. This quant researcher rehearses catastrophes in vivid detail before they happen and narrates the plan to whoever is nearby before committing to it. The instant the deadline moves up looks away from bad news in the hope it resolves unwitnessed — in the parts nobody grades, talks in win rate and never mentions size.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.67},{"slug":"recency","strength":0.6}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","anxious"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.67,"conscientiousness":0.43,"extraversion":0.64,"agreeableness":0.69,"neuroticism":0.76}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','anxious']::text[], 'Treats hesitation as the bigger risk. This quant researcher rehearses catastrophes in vivid detail before they happen and narrates the plan to whoever is nearby before committing to it. The instant the deadline moves up looks away from bad news in the hope it resolves unwitnessed — in the parts nobody grades, talks in win rate and never mentions size.', 0.92, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('b66da15d-74c7-4edf-887e-5bad3f2bde2e', 1, '{"big_five":{"openness":0.46,"conscientiousness":0.3,"extraversion":0.53,"agreeableness":0.61,"neuroticism":0.9},"dark_triad":{"machiavellianism":0.36,"narcissism":0.26,"psychopathy":0.37},"prospect_theory":{"lambda":3.29,"alpha":0.73,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Airdrop farmer, pronounced in style: needs repeated reassurance that a decision was the right one; is reliably surprised by deadlines that were never hidden. Buries hard calls under a pile of preparatory busywork. When the safe option quietly expires feels a loss twice as sharply as an equivalent gain and plans accordingly.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"disposition-effect","strength":0.71},{"slug":"loss-aversion","strength":0.76},{"slug":"availability","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.46,"conscientiousness":0.3,"extraversion":0.53,"agreeableness":0.61,"neuroticism":0.9}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Airdrop farmer, pronounced in style: needs repeated reassurance that a decision was the right one; is reliably surprised by deadlines that were never hidden. Buries hard calls under a pile of preparatory busywork. When the safe option quietly expires feels a loss twice as sharply as an equivalent gain and plans accordingly.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
