('4a0adf01-1d98-4014-bee1-810da17ab427', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.62,"extraversion":0.65,"agreeableness":0.33,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.65,"narcissism":0.71,"psychopathy":0.49},"prospect_theory":{"lambda":1.35,"alpha":0.94,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Liquidation-bot operator whose defining move is that they treats established procedure as a first draft to be rewritten. Wants the base rate before the anecdote. Builds in buffer time and then fills the buffer with more work. When someone is watching the outcome, holds their estimates with a certainty the track record does not support; keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.58},{"slug":"hindsight","strength":0.57}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.93,"conscientiousness":0.62,"extraversion":0.65,"agreeableness":0.33,"neuroticism":0.45}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Liquidation-bot operator whose defining move is that they treats established procedure as a first draft to be rewritten. Wants the base rate before the anecdote. Builds in buffer time and then fills the buffer with more work. When someone is watching the outcome, holds their estimates with a certainty the track record does not support; keeps a losing-trade journal they never re-read.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
