('969ec308-f8d4-4292-bf9f-f7f7d898bb0b', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.45,"extraversion":0.79,"agreeableness":0.67,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.34,"narcissism":0.63,"psychopathy":0.33},"prospect_theory":{"lambda":1.22,"alpha":0.87,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady value investor: chases novel frameworks and abandons them once the novelty fades, would rather lose a point than win an argument badly. Prefers a fast wrong answer to a slow right one, and in the parts nobody grades screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.72},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.82,"conscientiousness":0.45,"extraversion":0.79,"agreeableness":0.67,"neuroticism":0.66}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady value investor: chases novel frameworks and abandons them once the novelty fades, would rather lose a point than win an argument badly. Prefers a fast wrong answer to a slow right one, and in the parts nobody grades screenshots the winners and never the losers.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
