('66c9857d-6673-47a2-91d3-ac22e1a39fbc', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.88,"extraversion":0.48,"agreeableness":0.42,"neuroticism":0.15},"dark_triad":{"machiavellianism":0.85,"narcissism":0.46,"psychopathy":0.56},"prospect_theory":{"lambda":2.16,"alpha":0.94,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Delta-neutral market maker, pronounced in style: front-loads the work and double-checks it twice; chases novel frameworks and abandons them once the novelty fades. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Once things get tense is more certain than the hit rate justifies.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.74},{"slug":"recency","strength":0.51},{"slug":"anchoring","strength":0.57},{"slug":"optimism","strength":0.66}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","behavioral"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.88,"extraversion":0.48,"agreeableness":0.42,"neuroticism":0.15}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','behavioral']::text[], 'Delta-neutral market maker, pronounced in style: front-loads the work and double-checks it twice; chases novel frameworks and abandons them once the novelty fades. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Once things get tense is more certain than the hit rate justifies.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
