('a5535a10-6375-4c3f-b6a9-348947c1ae41', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.36,"extraversion":0.81,"agreeableness":0.61,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.36,"narcissism":0.64,"psychopathy":0.35},"prospect_theory":{"lambda":1.14,"alpha":0.86,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Is most certain precisely where their competence is thinnest. A steady options seller: recharges by being around people, not away from them, does the interesting 80% and abandons the tedious 20%. Trusts momentum over preparation, and in the parts nobody grades keeps three monitors for a portfolio that fits on one screen.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"fomo","strength":0.61},{"slug":"recency","strength":0.62},{"slug":"herd-behavior","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.73,"conscientiousness":0.36,"extraversion":0.81,"agreeableness":0.61,"neuroticism":0.56}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'Is most certain precisely where their competence is thinnest. A steady options seller: recharges by being around people, not away from them, does the interesting 80% and abandons the tedious 20%. Trusts momentum over preparation, and in the parts nobody grades keeps three monitors for a portfolio that fits on one screen.', 0.94, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
