('2eca49cd-8304-459e-8dc2-585ae6fda883', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.85,"extraversion":0.48,"agreeableness":0.32,"neuroticism":0.22},"dark_triad":{"machiavellianism":0.78,"narcissism":0.58,"psychopathy":0.6},"prospect_theory":{"lambda":2.38,"alpha":0.92,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Demands the data before the discussion and the discussion before the call. This macro allocator builds in buffer time and then fills the buffer with more work and says the blunt thing and enjoys the flinch. The instant the deadline moves up underestimates how often an obviously right call turns out wrong — left to their own devices, confuses a bull market for a trading edge.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.74},{"slug":"optimism","strength":0.66},{"slug":"recency","strength":0.52},{"slug":"hindsight","strength":0.7}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","behavioral"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.71,"conscientiousness":0.85,"extraversion":0.48,"agreeableness":0.32,"neuroticism":0.22}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','behavioral']::text[], 'Demands the data before the discussion and the discussion before the call. This macro allocator builds in buffer time and then fills the buffer with more work and says the blunt thing and enjoys the flinch. The instant the deadline moves up underestimates how often an obviously right call turns out wrong — left to their own devices, confuses a bull market for a trading edge.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('0709bbe6-6589-4aa1-b8a6-edb60f83ef13', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.61,"extraversion":0.69,"agreeableness":0.32,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.62,"narcissism":0.74,"psychopathy":0.41},"prospect_theory":{"lambda":1.07,"alpha":0.93,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Onchain copy-trader, pronounced in style: would rather invent a worse tool than use someone else''s good one; treats a quiet room as a problem to be solved. Treats a decision without a paper trail as a decision not yet made. The moment risk appears cannot watch a rally from the sidelines for long.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.62},{"slug":"hindsight","strength":0.59},{"slug":"recency","strength":0.57}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.61,"extraversion":0.69,"agreeableness":0.32,"neuroticism":0.49}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Onchain copy-trader, pronounced in style: would rather invent a worse tool than use someone else''s good one; treats a quiet room as a problem to be solved. Treats a decision without a paper trail as a decision not yet made. The moment risk appears cannot watch a rally from the sidelines for long.', 0.95, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('dda91830-80e3-434e-aad2-50f37a4ace91', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.46,"extraversion":0.81,"agreeableness":0.22,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.68,"narcissism":0.91,"psychopathy":0.58},"prospect_theory":{"lambda":0.76,"alpha":0.88,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Zero-DTE options gambler whose defining move is that they collects half-finished manifestos and unconventional methods. Knows the answer before it can explain the question. Narrates the plan to whoever is nearby before committing to it. Once the exit narrows to one door, abandons a private read the instant the crowd leans the other way; keeps three monitors for a portfolio that fits on one screen.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"bandwagon","strength":0.58},{"slug":"recency","strength":0.64}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.46,"extraversion":0.81,"agreeableness":0.22,"neuroticism":0.48}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'Zero-DTE options gambler whose defining move is that they collects half-finished manifestos and unconventional methods. Knows the answer before it can explain the question. Narrates the plan to whoever is nearby before committing to it. Once the exit narrows to one door, abandons a private read the instant the crowd leans the other way; keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
