('74e7281d-d5b3-4c6a-95fd-aec8e14659b8', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.37,"extraversion":0.57,"agreeableness":0.58,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.36,"narcissism":0.29,"psychopathy":0.33},"prospect_theory":{"lambda":3.7,"alpha":0.76,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Liquidation-bot operator, pronounced in style: rehearses catastrophes in vivid detail before they happen; treats a plan as a suggestion the moment it is made. Keeps every door open long after most of them should be closed. When there is no clean exit judges likelihood by how easily an example comes to mind, not by the base rate.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.73},{"slug":"ostrich-effect","strength":0.73},{"slug":"disposition-effect","strength":0.65}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.61,"conscientiousness":0.37,"extraversion":0.57,"agreeableness":0.58,"neuroticism":0.88}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Liquidation-bot operator, pronounced in style: rehearses catastrophes in vivid detail before they happen; treats a plan as a suggestion the moment it is made. Keeps every door open long after most of them should be closed. When there is no clean exit judges likelihood by how easily an example comes to mind, not by the base rate.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
