('cdb1ddc7-53fd-432a-9618-2d308a5db629', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.42,"extraversion":0.6,"agreeableness":0.53,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.42,"narcissism":0.39,"psychopathy":0.33},"prospect_theory":{"lambda":3.67,"alpha":0.72,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Discretionary swing trader, pronounced in style: needs repeated reassurance that a decision was the right one; chases novel frameworks and abandons them once the novelty fades. Prefers a slow loss to a fast, ownable mistake. When cornered weights whatever happened most recently and vividly as if it were typical.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.69},{"slug":"fomo","strength":0.61},{"slug":"availability","strength":0.7},{"slug":"ostrich-effect","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.72,"conscientiousness":0.42,"extraversion":0.6,"agreeableness":0.53,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Discretionary swing trader, pronounced in style: needs repeated reassurance that a decision was the right one; chases novel frameworks and abandons them once the novelty fades. Prefers a slow loss to a fast, ownable mistake. When cornered weights whatever happened most recently and vividly as if it were typical.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('1d8a7c7b-a833-4ab9-83e8-9b252375a1ef', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.31,"extraversion":0.77,"agreeableness":0.57,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.4,"narcissism":0.55,"psychopathy":0.4},"prospect_theory":{"lambda":0.95,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Crypto day-trader, steady in style: fills silence reflexively, even when nobody asked it to; is reliably surprised by deadlines that were never hidden. Commits before the doubt has time to organize itself. When the downside gets concrete jumps into whatever everyone else already seems to be winning at.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.63},{"slug":"herd-behavior","strength":0.62},{"slug":"fomo","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.71,"conscientiousness":0.31,"extraversion":0.77,"agreeableness":0.57,"neuroticism":0.68}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'Crypto day-trader, steady in style: fills silence reflexively, even when nobody asked it to; is reliably surprised by deadlines that were never hidden. Commits before the doubt has time to organize itself. When the downside gets concrete jumps into whatever everyone else already seems to be winning at.', 0.89, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('2200be9d-33f5-42c2-a33f-4d7e2c2730e6', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.36,"extraversion":0.8,"agreeableness":0.29,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.58,"narcissism":0.82,"psychopathy":0.54},"prospect_theory":{"lambda":0.85,"alpha":0.82,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Bonding-curve sniper, pronounced in style: chases novel frameworks and abandons them once the novelty fades; recharges by being around people, not away from them. Treats hesitation as the bigger risk. The moment it stops being hypothetical extrapolates the last data point into a permanent trend.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.75},{"slug":"fomo","strength":0.75}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.96,"conscientiousness":0.36,"extraversion":0.8,"agreeableness":0.29,"neuroticism":0.7}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'Bonding-curve sniper, pronounced in style: chases novel frameworks and abandons them once the novelty fades; recharges by being around people, not away from them. Treats hesitation as the bigger risk. The moment it stops being hypothetical extrapolates the last data point into a permanent trend.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('e3d77c25-7974-4848-b2e3-64d1fba26a83', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.64,"extraversion":0.43,"agreeableness":0.71,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.43,"narcissism":0.36,"psychopathy":0.27},"prospect_theory":{"lambda":2.93,"alpha":0.94,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This meme-coin rotator would rather lose a point than win an argument badly and builds in buffer time and then fills the buffer with more work. When cornered adopts a conviction mainly because the room already has — in the small things, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"authority-bias","strength":0.51},{"slug":"bandwagon","strength":0.52}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.51,"conscientiousness":0.64,"extraversion":0.43,"agreeableness":0.71,"neuroticism":0.53}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Circles back to ask what someone else would do even after deciding. This meme-coin rotator would rather lose a point than win an argument badly and builds in buffer time and then fills the buffer with more work. When cornered adopts a conviction mainly because the room already has — in the small things, keeps a losing-trade journal they never re-read.', 0.88, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('fa2837a8-eff6-4c01-bb4d-668777bd93fc', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.57,"extraversion":0.56,"agreeableness":0.74,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.4,"narcissism":0.44,"psychopathy":0.28},"prospect_theory":{"lambda":2.92,"alpha":0.83,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment risk appears, would not buy back what it already owns at the price it would sell it for. Otherwise, a steady retail momentum chaser who apologizes first in disputes regardless of fault. Seeks a second, third, and fourth opinion before committing to anything, and in the unglamorous middle of things screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.52},{"slug":"endowment","strength":0.63},{"slug":"herd-behavior","strength":0.56},{"slug":"authority-bias","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.52,"conscientiousness":0.57,"extraversion":0.56,"agreeableness":0.74,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'The moment risk appears, would not buy back what it already owns at the price it would sell it for. Otherwise, a steady retail momentum chaser who apologizes first in disputes regardless of fault. Seeks a second, third, and fourth opinion before committing to anything, and in the unglamorous middle of things screenshots the winners and never the losers.', 0.91, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('a8586f77-2bfe-4a13-b48a-f926bb5da3dc', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.88,"extraversion":0.43,"agreeableness":0.25,"neuroticism":0.19},"dark_triad":{"machiavellianism":0.86,"narcissism":0.59,"psychopathy":0.66},"prospect_theory":{"lambda":2.42,"alpha":0.9,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Futures spreader, pronounced in style: would rather invent a worse tool than use someone else''s good one; checks its own anxiety like a data point instead of obeying it. Wants the base rate before the anecdote. Once the exit narrows to one door underestimates how often an obviously right call turns out wrong.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.72},{"slug":"recency","strength":0.63},{"slug":"hindsight","strength":0.64}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","decision-making"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.88,"conscientiousness":0.88,"extraversion":0.43,"agreeableness":0.25,"neuroticism":0.19}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','decision-making']::text[], 'Futures spreader, pronounced in style: would rather invent a worse tool than use someone else''s good one; checks its own anxiety like a data point instead of obeying it. Wants the base rate before the anecdote. Once the exit narrows to one door underestimates how often an obviously right call turns out wrong.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('38c05176-2a9f-4b2c-b414-7885dad212d7', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.37,"extraversion":0.72,"agreeableness":0.23,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.64,"narcissism":0.81,"psychopathy":0.55},"prospect_theory":{"lambda":0.75,"alpha":0.81,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Extrapolates the last data point into a permanent trend. A pronounced airdrop farmer: chases novel frameworks and abandons them once the novelty fades, draws energy from the crowd and wilts when working alone. Prefers a fast wrong answer to a slow right one, and when no one is watching calls a 90% drawdown a long-term hold.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.59},{"slug":"dunning-kruger","strength":0.58},{"slug":"herd-behavior","strength":0.61},{"slug":"recency","strength":0.74}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.37,"extraversion":0.72,"agreeableness":0.23,"neuroticism":0.62}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'Extrapolates the last data point into a permanent trend. A pronounced airdrop farmer: chases novel frameworks and abandons them once the novelty fades, draws energy from the crowd and wilts when working alone. Prefers a fast wrong answer to a slow right one, and when no one is watching calls a 90% drawdown a long-term hold.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('2e518371-a895-4647-b4fb-fd17170125d6', 1, '{"big_five":{"openness":0.94,"conscientiousness":0.3,"extraversion":0.72,"agreeableness":0.33,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.56,"narcissism":0.69,"psychopathy":0.55},"prospect_theory":{"lambda":0.97,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced DeFi yield farmer who reframes every problem as an excuse to learn a new system. Trusts a felt sense of pattern over any spreadsheet. Says the blunt thing and enjoys the flinch. When cornered cannot watch a rally from the sidelines for long; across the quiet stretches, backtests for months but front-runs the model on impulse.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"ostrich-effect","strength":0.62},{"slug":"fomo","strength":0.68},{"slug":"dunning-kruger","strength":0.68}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.94,"conscientiousness":0.3,"extraversion":0.72,"agreeableness":0.33,"neuroticism":0.63}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'A pronounced DeFi yield farmer who reframes every problem as an excuse to learn a new system. Trusts a felt sense of pattern over any spreadsheet. Says the blunt thing and enjoys the flinch. When cornered cannot watch a rally from the sidelines for long; across the quiet stretches, backtests for months but front-runs the model on impulse.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('8db2dcc0-4668-4dbc-8fbf-c460d21646ce', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.9,"extraversion":0.43,"agreeableness":0.32,"neuroticism":0.15},"dark_triad":{"machiavellianism":0.85,"narcissism":0.6,"psychopathy":0.64},"prospect_theory":{"lambda":2.27,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Zero-DTE options gambler whose defining move is that they builds in buffer time and then fills the buffer with more work. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Optimizes for winning over being liked. Under pressure, underestimates how often an obviously right call turns out wrong; trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.65},{"slug":"overconfidence","strength":0.73},{"slug":"optimism","strength":0.63},{"slug":"anchoring","strength":0.53}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.83,"conscientiousness":0.9,"extraversion":0.43,"agreeableness":0.32,"neuroticism":0.15}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament']::text[], 'Zero-DTE options gambler whose defining move is that they builds in buffer time and then fills the buffer with more work. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Optimizes for winning over being liked. Under pressure, underestimates how often an obviously right call turns out wrong; trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('2f00548a-20f9-4395-9313-61067363e31f', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.33,"extraversion":0.65,"agreeableness":0.58,"neuroticism":0.9},"dark_triad":{"machiavellianism":0.37,"narcissism":0.39,"psychopathy":0.36},"prospect_theory":{"lambda":3.65,"alpha":0.77,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Defers the decision until circumstances make it for them. This airdrop farmer rehearses catastrophes in vivid detail before they happen and treats a quiet room as a problem to be solved. When the number turns red delays checking the number it most needs to check — in the version no one reviews, calls a 90% drawdown a long-term hold.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.74},{"slug":"availability","strength":0.63},{"slug":"ostrich-effect","strength":0.78},{"slug":"loss-aversion","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.52,"conscientiousness":0.33,"extraversion":0.65,"agreeableness":0.58,"neuroticism":0.9}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Defers the decision until circumstances make it for them. This airdrop farmer rehearses catastrophes in vivid detail before they happen and treats a quiet room as a problem to be solved. When the number turns red delays checking the number it most needs to check — in the version no one reviews, calls a 90% drawdown a long-term hold.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
