('601da428-38c3-43c4-985a-546c15bd6c1b', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.85,"extraversion":0.4,"agreeableness":0.34,"neuroticism":0.17},"dark_triad":{"machiavellianism":0.85,"narcissism":0.52,"psychopathy":0.59},"prospect_theory":{"lambda":2.31,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Delta-neutral market maker whose defining move is that they plans in exhaustive detail and resents any deviation. Builds a decision matrix for choices most people make on instinct. Treats a crisis as an interesting problem rather than a threat. Under a deadline, holds their estimates with a certainty the track record does not support; averages down on a name three times in a week.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.59},{"slug":"overconfidence","strength":0.79},{"slug":"hindsight","strength":0.61}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.8,"conscientiousness":0.85,"extraversion":0.4,"agreeableness":0.34,"neuroticism":0.17}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo']::text[], 'Delta-neutral market maker whose defining move is that they plans in exhaustive detail and resents any deviation. Builds a decision matrix for choices most people make on instinct. Treats a crisis as an interesting problem rather than a threat. Under a deadline, holds their estimates with a certainty the track record does not support; averages down on a name three times in a week.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
