('3526245a-2515-481f-af81-a6601993b687', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.35,"extraversion":0.54,"agreeableness":0.61,"neuroticism":0.9},"dark_triad":{"machiavellianism":0.39,"narcissism":0.26,"psychopathy":0.36},"prospect_theory":{"lambda":3.49,"alpha":0.71,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced index-fund holdout who spirals on ambiguity and mistakes the spiral for diligence. Prefers a slow loss to a fast, ownable mistake. Improvises past every deadline and calls it flexibility. Under a deadline looks away from bad news in the hope it resolves unwitnessed; once the urgency drains out, checks the P&L blotter forty times before lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.66},{"slug":"ostrich-effect","strength":0.79},{"slug":"recency","strength":0.7},{"slug":"disposition-effect","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.56,"conscientiousness":0.35,"extraversion":0.54,"agreeableness":0.61,"neuroticism":0.9}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'A pronounced index-fund holdout who spirals on ambiguity and mistakes the spiral for diligence. Prefers a slow loss to a fast, ownable mistake. Improvises past every deadline and calls it flexibility. Under a deadline looks away from bad news in the hope it resolves unwitnessed; once the urgency drains out, checks the P&L blotter forty times before lunch.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
