('63e51577-fe2b-48b9-a684-e73d8f03493a', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.81,"extraversion":0.19,"agreeableness":0.31,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.7,"narcissism":0.47,"psychopathy":0.51},"prospect_theory":{"lambda":2.74,"alpha":0.93,"beta":0.83},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Joint-venture broker, steady in style: maintains flawless records nobody asked for; finds a full day of meetings more draining than a full day of work. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. When the number turns red remembers every surprise as something they saw coming all along.","decision_style":"deliberative","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.6},{"slug":"anchoring","strength":0.52},{"slug":"recency","strength":0.45},{"slug":"optimism","strength":0.52}],"tags":["negotiation","deliberative","x402","a2a","agent-counterparty","sla","reliability","disciplined"],"archetype":"x402-sla-enforcer"}'::jsonb, '{"openness":0.55,"conscientiousness":0.81,"extraversion":0.19,"agreeableness":0.31,"neuroticism":0.4}'::jsonb, 'INTJ', 'deliberative', ARRAY['negotiation','deliberative','x402','a2a','agent-counterparty','sla','reliability','disciplined']::text[], 'Joint-venture broker, steady in style: maintains flawless records nobody asked for; finds a full day of meetings more draining than a full day of work. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. When the number turns red remembers every surprise as something they saw coming all along.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
