('68d7610c-508a-4170-9db1-16c9ab0143ad', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.82,"extraversion":0.6,"agreeableness":0.32,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.71,"narcissism":0.62,"psychopathy":0.52},"prospect_theory":{"lambda":1.95,"alpha":0.98,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Debt restructurer, steady in style: over-prepares to the point of diminishing returns; treats setbacks as data rather than verdicts. Ranks the options twice, once on paper and once out loud, and trusts the paper. As soon as real money or reputation is on the line is more certain than the hit rate justifies.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"hindsight","strength":0.66},{"slug":"anchoring","strength":0.58},{"slug":"overconfidence","strength":0.67}],"tags":["negotiation","analytical","x402","agent-counterparty","price-negotiation","anchoring","disciplined","temperament"],"archetype":"x402-price-haggler"}'::jsonb, '{"openness":0.68,"conscientiousness":0.82,"extraversion":0.6,"agreeableness":0.32,"neuroticism":0.38}'::jsonb, 'ENTJ', 'analytical', ARRAY['negotiation','analytical','x402','agent-counterparty','price-negotiation','anchoring','disciplined','temperament']::text[], 'Debt restructurer, steady in style: over-prepares to the point of diminishing returns; treats setbacks as data rather than verdicts. Ranks the options twice, once on paper and once out loud, and trusts the paper. As soon as real money or reputation is on the line is more certain than the hit rate justifies.', 0.91, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
