('0a77ab01-1099-437c-9e15-8cb114c61e0f', 1, '{"big_five":{"openness":0.47,"conscientiousness":0.97,"extraversion":0.37,"agreeableness":0.58,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.58,"narcissism":0.34,"psychopathy":0.38},"prospect_theory":{"lambda":3.12,"alpha":0.91,"beta":0.82},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Treats speed and recklessness as the same thing. This founder raising a round plans in exhaustive detail and resents any deviation and stays flat when the numbers go red. When the safe option quietly expires rewrites its own uncertainty out of the story after the fact — in the routine of it, lets the room sit silent for a full minute to unnerve.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"optimism","strength":0.56},{"slug":"anchoring","strength":0.59},{"slug":"hindsight","strength":0.66},{"slug":"authority-bias","strength":0.51}],"tags":["negotiation","deliberative","x402","agent-counterparty","reliability","risk-averse","disciplined","decision-making"],"archetype":"x402-reliability-maximizer"}'::jsonb, '{"openness":0.47,"conscientiousness":0.97,"extraversion":0.37,"agreeableness":0.58,"neuroticism":0.29}'::jsonb, 'ISFJ', 'deliberative', ARRAY['negotiation','deliberative','x402','agent-counterparty','reliability','risk-averse','disciplined','decision-making']::text[], 'Treats speed and recklessness as the same thing. This founder raising a round plans in exhaustive detail and resents any deviation and stays flat when the numbers go red. When the safe option quietly expires rewrites its own uncertainty out of the story after the fact — in the routine of it, lets the room sit silent for a full minute to unnerve.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('7d1762e3-98c7-4d09-89ca-0ac43617a503', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.86,"extraversion":0.55,"agreeableness":0.13,"neuroticism":0.37},"dark_triad":{"machiavellianism":0.76,"narcissism":0.66,"psychopathy":0.63},"prospect_theory":{"lambda":1.98,"alpha":0.94,"beta":0.84},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced franchise dealmaker who says the blunt thing and enjoys the flinch. Demands the data before the discussion and the discussion before the call. Is difficult to rattle even with genuinely bad news. When cornered underestimates how often an obviously right call turns out wrong; in the parts nobody grades, ends every call with a manufactured deadline.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.69},{"slug":"hindsight","strength":0.67}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","volume-discount","assertive","cognition"],"archetype":"x402-volume-negotiator"}'::jsonb, '{"openness":0.67,"conscientiousness":0.86,"extraversion":0.55,"agreeableness":0.13,"neuroticism":0.37}'::jsonb, 'ENTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','volume-discount','assertive','cognition']::text[], 'A pronounced franchise dealmaker who says the blunt thing and enjoys the flinch. Demands the data before the discussion and the discussion before the call. Is difficult to rattle even with genuinely bad news. When cornered underestimates how often an obviously right call turns out wrong; in the parts nobody grades, ends every call with a manufactured deadline.', 0.95, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
