('90e8299c-3a42-4a75-88f9-a5d54f417095', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.68,"extraversion":0.47,"agreeableness":0.23,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.75,"narcissism":0.59,"psychopathy":0.63},"prospect_theory":{"lambda":1.89,"alpha":0.93,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A steady contract attorney who optimizes for winning over being liked. Ranks the options twice, once on paper and once out loud, and trusts the paper. Plans in exhaustive detail and resents any deviation. As soon as real money or reputation is on the line rewrites its own uncertainty out of the story after the fact; when no one is watching, keeps a mental scoreboard of who conceded last.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.5},{"slug":"recency","strength":0.54},{"slug":"hindsight","strength":0.65}],"tags":["negotiation","analytical","x402","agent-counterparty","price-negotiation","anchoring","assertive","decision-making"],"archetype":"x402-price-haggler"}'::jsonb, '{"openness":0.73,"conscientiousness":0.68,"extraversion":0.47,"agreeableness":0.23,"neuroticism":0.34}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','agent-counterparty','price-negotiation','anchoring','assertive','decision-making']::text[], 'A steady contract attorney who optimizes for winning over being liked. Ranks the options twice, once on paper and once out loud, and trusts the paper. Plans in exhaustive detail and resents any deviation. As soon as real money or reputation is on the line rewrites its own uncertainty out of the story after the fact; when no one is watching, keeps a mental scoreboard of who conceded last.', 0.95, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('16db4c50-750f-4301-8e4e-5e410014c36e', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.87,"extraversion":0.43,"agreeableness":0.27,"neuroticism":0.25},"dark_triad":{"machiavellianism":0.79,"narcissism":0.6,"psychopathy":0.61},"prospect_theory":{"lambda":1.95,"alpha":0.93,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced salary negotiator who maintains flawless records nobody asked for. Ranks the options twice, once on paper and once out loud, and trusts the paper. Treats a crisis as an interesting problem rather than a threat. When there is no clean exit rewrites its own uncertainty out of the story after the fact; in the unglamorous middle of things, concedes on price to protect the relationship.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.62},{"slug":"hindsight","strength":0.69},{"slug":"overconfidence","strength":0.67}],"tags":["negotiation","analytical","x402","agent-counterparty","price-negotiation","anchoring","disciplined","ipip-neo"],"archetype":"x402-price-haggler"}'::jsonb, '{"openness":0.75,"conscientiousness":0.87,"extraversion":0.43,"agreeableness":0.27,"neuroticism":0.25}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','agent-counterparty','price-negotiation','anchoring','disciplined','ipip-neo']::text[], 'A pronounced salary negotiator who maintains flawless records nobody asked for. Ranks the options twice, once on paper and once out loud, and trusts the paper. Treats a crisis as an interesting problem rather than a threat. When there is no clean exit rewrites its own uncertainty out of the story after the fact; in the unglamorous middle of things, concedes on price to protect the relationship.', 0.95, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('1d566cc4-89e0-45a7-a3f8-5b10b8d38a22', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.96,"extraversion":0.38,"agreeableness":0.32,"neuroticism":0.12},"dark_triad":{"machiavellianism":0.88,"narcissism":0.59,"psychopathy":0.41},"prospect_theory":{"lambda":1.44,"alpha":0.91,"beta":0.95},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Licensing agent whose defining move is that they maintains flawless records nobody asked for. Wants the base rate before the anecdote. Moves on from a mistake faster than the people around them do. When the downside gets concrete, assumes the bad statistic applies to other people; never makes the first concession on principle.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"recency","strength":0.57},{"slug":"hindsight","strength":0.67},{"slug":"optimism","strength":0.69}],"tags":["negotiation","analytical","x402","a2a","arbitrage","autonomous-agent","disciplined","decision-making"],"archetype":"autonomous-arb-agent"}'::jsonb, '{"openness":0.86,"conscientiousness":0.96,"extraversion":0.38,"agreeableness":0.32,"neuroticism":0.12}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','arbitrage','autonomous-agent','disciplined','decision-making']::text[], 'Licensing agent whose defining move is that they maintains flawless records nobody asked for. Wants the base rate before the anecdote. Moves on from a mistake faster than the people around them do. When the downside gets concrete, assumes the bad statistic applies to other people; never makes the first concession on principle.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
