('c412eec9-d345-437c-b3d7-0a71d3b5424a', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.9,"extraversion":0.41,"agreeableness":0.37,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.81,"narcissism":0.56,"psychopathy":0.53},"prospect_theory":{"lambda":1.88,"alpha":0.94,"beta":0.94},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"The instant it becomes irreversible, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced corporate liquidator who over-prepares to the point of diminishing returns and reads outside the field for ideas the field itself would reject. Converts every argument into a number it can compare against another number, and across an ordinary week never signs on the first draft out of habit.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.56},{"slug":"overconfidence","strength":0.64},{"slug":"hindsight","strength":0.63},{"slug":"recency","strength":0.56}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","volume-discount","disciplined","temperament"],"archetype":"x402-volume-negotiator"}'::jsonb, '{"openness":0.78,"conscientiousness":0.9,"extraversion":0.41,"agreeableness":0.37,"neuroticism":0.28}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','volume-discount','disciplined','temperament']::text[], 'The instant it becomes irreversible, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced corporate liquidator who over-prepares to the point of diminishing returns and reads outside the field for ideas the field itself would reject. Converts every argument into a number it can compare against another number, and across an ordinary week never signs on the first draft out of habit.', 0.98, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('2b48b62c-10cf-457a-84d6-73c774b9f59a', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.81,"extraversion":0.43,"agreeableness":0.37,"neuroticism":0.24},"dark_triad":{"machiavellianism":0.63,"narcissism":0.49,"psychopathy":0.52},"prospect_theory":{"lambda":1.72,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Partnerships director whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Ranks the options twice, once on paper and once out loud, and trusts the paper. Optimizes for winning over being liked. When the safe option quietly expires, remembers every surprise as something they saw coming all along; keeps a mental scoreboard of who conceded last.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"anchoring","strength":0.6},{"slug":"overconfidence","strength":0.65},{"slug":"hindsight","strength":0.67},{"slug":"recency","strength":0.52}],"tags":["negotiation","analytical","x402","agent-counterparty","price-negotiation","anchoring","disciplined","decision-making"],"archetype":"x402-price-haggler"}'::jsonb, '{"openness":0.7,"conscientiousness":0.81,"extraversion":0.43,"agreeableness":0.37,"neuroticism":0.24}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','agent-counterparty','price-negotiation','anchoring','disciplined','decision-making']::text[], 'Partnerships director whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Ranks the options twice, once on paper and once out loud, and trusts the paper. Optimizes for winning over being liked. When the safe option quietly expires, remembers every surprise as something they saw coming all along; keeps a mental scoreboard of who conceded last.', 0.97, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
