('d15cd06d-6e33-4f0f-b0f2-ce9eb86d03da', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.94,"extraversion":0.35,"agreeableness":0.61,"neuroticism":0.32},"dark_triad":{"machiavellianism":0.62,"narcissism":0.41,"psychopathy":0.37},"prospect_theory":{"lambda":3.06,"alpha":0.95,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Founder raising a round, pronounced in style: maintains flawless records nobody asked for; says the least in the room and notices the most. Keeps deliberating past the point where more information would change anything. The instant it becomes irreversible never quite escapes the first figure it heard, however arbitrary.","decision_style":"deliberative","mbti_label":"INFJ","suggested_biases":[{"slug":"overconfidence","strength":0.52},{"slug":"anchoring","strength":0.59}],"tags":["negotiation","deliberative","x402","agent-counterparty","reliability","risk-averse","disciplined","behavioral"],"archetype":"x402-reliability-maximizer"}'::jsonb, '{"openness":0.56,"conscientiousness":0.94,"extraversion":0.35,"agreeableness":0.61,"neuroticism":0.32}'::jsonb, 'INFJ', 'deliberative', ARRAY['negotiation','deliberative','x402','agent-counterparty','reliability','risk-averse','disciplined','behavioral']::text[], 'Founder raising a round, pronounced in style: maintains flawless records nobody asked for; says the least in the room and notices the most. Keeps deliberating past the point where more information would change anything. The instant it becomes irreversible never quite escapes the first figure it heard, however arbitrary.', 0.96, 'approved', '23f52993-d83a-4722-a8af-d91ec112c7a4'),
